import React, { useState } from 'react';
import './App.css';
import EndPage from './component/cards/EndPage';
import GameBord from './component/cards/GameBord';
import Login from './component/Login';

const pages= {home:"home" , game:"game" }

function App() {
  const [page, setPage] = useState(pages.home)
  const [playerName, setPlayerName] = useState("")
  const [cards, setCards] = useState({})
  const [players, setPlayers] = useState([])

  let savePalyerName=(name)=>{
    setPlayerName(name)
  }

  let changePage=(newPage)=>{
    setPage(newPage)
  }
  let saveInfo=(name , didWin)=>{
    let playersList= players
    let isNewPlayer = false
    for(let i=0;i<playersList.length;i++){
      if (playersList[i].name==name){
        if(didWin)
        playersList[i]={name:playersList[i].name ,games:playersList[i].games+1,winnings:playersList[i].winnings+1}
        else 
        playersList[i]={name:playersList[i].name ,games:playersList[i].games+1,winnings:playersList[i].winnings}
        isNewPlayer=false
        break
      }
      else
      isNewPlayer=true
    }
    if(isNewPlayer){
      if(didWin)
        playersList.push({name:name ,games:1,winnings:1})
        else 
        playersList.push({name:name ,games:1,winnings:0})
    }
setPlayers(playersList)
  }

let theList=()=>{
  return <playersList players/>
}


let displayPage=()=>{
  switch(page){
    case pages.home:
    return <Login savePlayerName={savePalyerName} pages= {pages} currentPage={changePage}  />
    case pages.game:
      return <GameBord playerName={playerName} saveInfo={saveInfo} pages= {pages} currentPage={changePage}/>

  }
}


  return (
    <div>
      {displayPage()}
    </div>)
}
export default App;
